import React from 'react';
import AnimationArrows from '../../atomic/atoms/AnimationArrows';
import BasicScreen from '../../atomic/templates/BasicScreen';
import ApiError from '../../atomic/organisms/ApiError';
import { WebViewScreen } from '../../atomic/templates/WebViewScreen';
import { useAirlineMilesMarketplace } from './index';
import type { AirlineMilesMarketplaceScreenProps } from './Models';

const SCREEN_TITLE = 'Milhas Aéreas';

export default function AirlineMilesMarketplaceScreen(props: AirlineMilesMarketplaceScreenProps) {
  const {
    isWebViewError,
    redirectURL,
    isLoading,
    isError,
    webViewRef,
    handleGoBack,
    handleWebViewError,
    handleRetry,
  } = useAirlineMilesMarketplace(props);

  if (isLoading) {
    return <AnimationArrows />;
  }

  if (isError || !redirectURL || isWebViewError) {
    return (
      <BasicScreen
        leftIconOnPress={handleGoBack}
        title={SCREEN_TITLE}
        errorButtonOnPress={handleRetry}
      >
        <ApiError onPress={handleRetry} />
      </BasicScreen>
    );
  }

  return (
    <WebViewScreen
      uri={redirectURL}
      title={SCREEN_TITLE}
      webViewRef={webViewRef}
      onBackPress={handleGoBack}
      onError={handleWebViewError}
      onRetry={handleRetry}
    />
  );
}

import React from 'react'

import { bindActionCreators, Dispatch } from 'redux'
import { connect } from 'react-redux'

import { Creators as ExampleActions, State as ExampleType } from '~/redux/ducks/example'
import { CustomerActions } from '@semparar/mf-app-user';

import { Props } from './Models'

import ExampleView from './view'

const Example: React.FC<Props> = ({
	requestExample,
	isLoading,
	logout,
}) => {
	return (
		<ExampleView 
			requestExample={requestExample} 
			isLoading={isLoading}
			logout={() => logout(true)}
		/>
	)
}

const mapStateToProps = ({ 
     exampleReducer
}: {
	exampleReducer: ExampleType,
}) => ({
	isLoading: exampleReducer.isLoading,
})

const mapDispatchToProps = (dispatch: Dispatch) => {
	return bindActionCreators({
		...ExampleActions,
		...CustomerActions,
    }, dispatch)
}

export default connect(mapStateToProps, mapDispatchToProps)(Example)

import React, { useState } from 'react'

import { Button, TextInput } from 'react-native'

import { Box, Text } from '@semparar/design-system-app';

import { PropsView } from './Models'
import Screen from '~/atomic/templates/Screen';

const ExampleView: React.FC<PropsView> = ({
    requestExample,
    logout,
}) => {
    const [test1, setTest1] = useState<string>("")
    const [test2, setTest2] = useState<string>("")
	return (
        <Screen title='Example'>
            <Box width="100%">
                <Text mr="medium">Clique para atualizar</Text>
            </Box>
            <TextInput 
                accessibilityLabel='Teste'
                onChangeText={(text: string) => setTest1(text)}
                value={test1}
            />
            <TextInput 
                accessibilityLabel='Teste 2'
                onChangeText={(text: string) => setTest2(text)}
                value={test2}
            />
            <Button
                title='Finalizar'
                accessibilityLabel='Finalizar'
                onPress={() => requestExample({
                    test1,
                    test2,
                })}
            />
            <Button
                title='Sair'
                accessibilityLabel='Sair'
                onPress={logout}
            />
        </Screen>
	)
}

export default ExampleView

