import { useCallback, useEffect, useRef, useState } from 'react';
import { useFocusEffect } from '@react-navigation/native';
import { WebViewProps as RNWebViewProps } from 'react-native-webview';
import { useScreenViewTracking } from '../../hooks/tracking';
import { useMarketplace } from '../../services/hooks/useMarketplace';
import AnimationArrows from '../../atomic/atoms/AnimationArrows';
import BasicScreen from '../../atomic/templates/BasicScreen';
import ApiError from '../../atomic/organisms/ApiError';
import MarketplaceView from './view';
import type {
  MarketplaceScreenProps,
  UseMarketplaceReturn,
} from './Models';

export function useMarketplaceScreen(
  props: MarketplaceScreenProps
): UseMarketplaceReturn {
  const { navigation, route } = props;
  useScreenViewTracking({ route, title: 'Shopping' });

  const [isWebViewError, setIsWebViewError] = useState(false);
  const webViewRef = useRef<RNWebViewProps>(null);

  const {
    redirectURL,
    isLoading,
    isError,
    fetchMarketplaceToken,
    reset,
  } = useMarketplace();

  useFocusEffect(
    useCallback(() => {
      let isActive = true;

      const fetchData = async () => {
        if (isActive) {
          setIsWebViewError(false);
        }
        await fetchMarketplaceToken();
      };

      fetchData();

      return () => {
        isActive = false;
      };
    }, [fetchMarketplaceToken])
  );

  useEffect(() => {
    return () => {
      reset();
    };
  }, [reset]);

  const handleGoBack = useCallback(() => {
    navigation.goBack();
  }, [navigation]);

  const handleWebViewError = useCallback(() => {
    setIsWebViewError(true);
  }, []);

  const handleRetry = useCallback(() => {
    setIsWebViewError(false);
    fetchMarketplaceToken();
  }, [fetchMarketplaceToken]);

  return {
    isWebViewError,
    redirectURL,
    isLoading,
    isError,
    webViewRef,
    handleGoBack,
    handleWebViewError,
    handleRetry,
  };
}

export default function MarketplaceScreen(props: MarketplaceScreenProps) {
  const {
    isWebViewError,
    redirectURL,
    isLoading,
    isError,
    webViewRef,
    handleGoBack,
    handleWebViewError,
    handleRetry,
  } = useMarketplaceScreen(props);

  if (isLoading) {
    return <AnimationArrows />;
  }

  if (isError || !redirectURL || isWebViewError) {
    return (
      <BasicScreen
        leftIconOnPress={handleGoBack}
        title="Shopping"
        errorButtonOnPress={handleRetry}
      >
        <ApiError onPress={handleRetry} />
      </BasicScreen>
    );
  }

  return (
    <MarketplaceView
      uri={redirectURL}
      webViewRef={webViewRef}
      onBackPress={handleGoBack}
      onError={handleWebViewError}
      errorButtonOnPress={handleRetry}
    />
  );
}

